import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"Java auf macOS installieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Installation von Java auf macOS.","frontmatter":{"title":"Java auf macOS installieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Installation von Java auf macOS.","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"de_de/players/installing-java/macos.md","filePath":"translated/de_de/players/installing-java/macos.md","lastUpdated":1770561656000}`);var c={name:`de_de/players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Java auf macOS installieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Java auf macOS installieren”">​</a></h1><p>Diese Anleitung führt Sie durch die Installation von Java 21 auf macOS.</p><p>Der Minecraft Launcher kommt bereits mit seiner eigenen Java Installation, diese Sektion ist also nur relevant, wenn du den auf der Fabric <code>.jar</code> basierenden Installer oder die Minecraft Server <code>.jar</code> verwenden möchtest.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Überprüfe, ob Java bereits installiert ist <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Überprüfe, ob Java bereits installiert ist”">​</a></h2><p>Gebe in das Terminal (zu finden unter <code>/Applications/Utilities/Terminal.app</code>) Folgendes ein und drücke die <kbd>Eingabetaste</kbd>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Du solltest etwa Folgendes sehen:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Beachten die Versionsnummer: Im obigen Beispiel lautet sie <code>21.0.9</code>.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Um Minecraft 1.21.11 zu verwenden, musst du mindestens Java 21 installiert haben.</p><p>Wenn dieser Befehl, eine Version kleiner als 21 anzeigt, musst du deine existierende Java Installation aktualisieren; lies diese Seite weiter.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Herunterladen und Installieren von Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Herunterladen und Installieren von Java 21”">​</a></h2><p>Wir empfehlen die Verwendung von <a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptiums Build von OpenJDK 21</a>:</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Temurin Java Download Seite" loading="lazy"></p><p>Stelle sicher die Version &quot;21 – LTS&quot; auszuwählen und das Installer Format <code>.PKG</code> auszuwählen. Du solltest auch die richtige Architektur entsprechend dem Prozessor deines Systems auswählen:</p><ul><li>Wenn du einen Apple M-Serie Prozessor hast, wähle <code>aarch64</code> (der Standard)</li><li>Wenn du einen Intel Prozessor hast, wähle <code>x64</code></li><li>Folge diesen <a href="https://support.apple.com/en-us/116943" target="_blank" rel="noreferrer">Anweisungen, um zu wissen, welcher Prozessor sich in deinem Mac befindet</a></li></ul><p>Nach dem Download des <code>.pkg</code> Installer, öffne diese und folge den Aufforderungen:</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Temurin Java Installer" loading="lazy"></p><p>Du wirst dein Administrator Passwort eingeben müssen, um die Installation abzuschließen:</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="macOS Aufforderung zur Passwort Eingabe" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">Homebrew verwenden <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “Homebrew verwenden”">​</a></h3><p>Wenn du bereits <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a> installiert hast, kannst du stattdessen Java 21 mit <code>brew</code> installieren:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Verifiziere, dass Java 21 installiert ist <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Verifiziere, dass Java 21 installiert ist”">​</a></h2><p>Sobald die Installation abgeschlossen ist, kannst du überprüfen, ob Java 21 aktiv ist, indem du das Terminal erneut öffnest und <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code> eingibst.</p><p>Wenn der Befehl erfolgreich ist, solltest du etwa Folgendes sehen:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Wenn du Probleme hast, kannst du gerne im <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> um Hilfe bitten.</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};